#include <iostream>
using namespace std;

// Inline function declaration
inline int square(int x) {
 return x * x;
}

// Inline function with multiple parameters
inline int max(int a, int b) {
 return (a > b) ? a : b;
}

int main() {
 int num = 5;
 int result = square(num); // Replaced with: return num * num;
 cout << "Square of " << num << " is " << result << endl;

 int a = 10, b = 20;
 cout << "Maximum is: " << max(a, b) << endl; // Inlined

 return 0;
}

#include <iostream>
using namespace std;

// Small function - good inline candidate
inline int add(int a, int b) {
 return a + b;
}

// Large function - compiler may ignore inline
inline int calculateFactorial(int n) {
 int result = 1;
 for(int i = 1; i <= n; i++) {
 result *= i;
 }
 return result;
}

// Recursive function - should NOT be inlined
inline int fibonacci(int n) {
 if(n <= 1) return n;
 return fibonacci(n-1) + fibonacci(n-2); // Compiler won't inline
}

int main() {
 cout << "Add: " << add(5, 3) << endl; // Likely inlined
 cout << "Factorial: " << calculateFactorial(5) << endl; // May not inline
 cout << "Fibonacci: " << fibonacci(5) << endl; // Not inlined
 return 0;
}

#include <iostream>
using namespace std;

// Class with implicit inline (defined inside class)
class Calculator {
private:
 int value;
public:
 // Implicitly inline - defined inside class
 int getValue() {
 return value;
 }

 void setValue(int v) {
 value = v;
 }

 // Explicitly inline - defined outside but marked
 inline int square();

 inline int cube();
};

// Explicit inline definition outside class
inline int Calculator::square() {
 return value * value;
}

inline int Calculator::cube() {
 return value * value * value;
}

int main() {
 Calculator calc;
 calc.setValue(5);
 cout << "Value: " << calc.getValue() << endl;
 cout << "Square: " << calc.square() << endl;
 cout << "Cube: " << calc.cube() << endl;
 return 0;
}
